import React, { useState, useEffect } from 'react';
import { cities, recommendations } from '../utils/api';

const BudgetRecommendations = () => {
  const [cityList, setCityList] = useState([]);
  const [selectedCity, setSelectedCity] = useState('');
  const [budget, setBudget] = useState('');
  const [recommendedPlaces, setRecommendedPlaces] = useState([]);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    fetchCities();
  }, []);

  const fetchCities = async () => {
    try {
      const response = await cities.getAll();
      setCityList(response.data);
    } catch (error) {
      console.error('Failed to fetch cities:', error);
    }
  };

  const handleGetRecommendations = async (e) => {
    e.preventDefault();
    if (!selectedCity || !budget) return;

    setLoading(true);
    try {
      const response = await recommendations.getBudgetRecommendations({
        city_id: selectedCity,
        budget: parseFloat(budget)
      });
      setRecommendedPlaces(response.data.recommendations || []);
    } catch (error) {
      console.error('Failed to get recommendations:', error);
      alert('Failed to get recommendations');
    } finally {
      setLoading(false);
    }
  };

  const addToItinerary = (place) => {
    const itinerary = JSON.parse(localStorage.getItem('itinerary') || '[]');
    const exists = itinerary.find(item => item.id === place.id);

    if (!exists) {
      itinerary.push(place);
      localStorage.setItem('itinerary', JSON.stringify(itinerary));
      alert(`${place.name} added to itinerary!`);
    } else {
      alert(`${place.name} is already in your itinerary!`);
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>Budget Recommendations</h1>
        <p style={styles.subtitle}>Get optimized place recommendations within your budget</p>
      </div>

      <div style={styles.formContainer}>
        <form onSubmit={handleGetRecommendations} style={styles.form}>
          <div style={styles.formRow}>
            <div style={styles.formField}>
              <label style={styles.label}>Select City:</label>
              <select
                value={selectedCity}
                onChange={(e) => setSelectedCity(e.target.value)}
                style={styles.select}
                required
              >
                <option value="">Choose a city</option>
                {cityList.map(city => (
                  <option key={city.id} value={city.id}>{city.name}</option>
                ))}
              </select>
            </div>
            <div style={styles.formField}>
              <label style={styles.label}>Budget (NPR):</label>
              <input
                type="number"
                value={budget}
                onChange={(e) => setBudget(e.target.value)}
                style={styles.input}
                placeholder="Enter your budget"
                required
              />
            </div>
          </div>
          <button type="submit" style={styles.submitButton} disabled={loading}>
            {loading ? 'Getting Recommendations...' : 'Get Recommendations'}
          </button>
        </form>
      </div>

      {recommendedPlaces.length > 0 && (
        <div style={styles.resultsContainer}>
          <h2 style={styles.resultsTitle}>Recommended Places</h2>
          <div style={styles.placesGrid}>
            {recommendedPlaces.map(place => (
              <div key={place.id} style={styles.placeCard}>
                {place.image_url && (
                  <img 
                    src={`http://localhost:5000${place.image_url}`} 
                    alt={place.name}
                    style={styles.placeImage}
                  />
                )}
                <div style={styles.cardContent}>
                  <h3 style={styles.placeName}>{place.name}</h3>
                  <p style={styles.placeType}>{place.type}</p>
                  <p style={styles.price}>NPR {place.price}</p>
                  <p style={styles.rating}>★ {place.rating}</p>
                  <button 
                    onClick={() => addToItinerary(place)}
                    style={styles.addButton}
                  >
                    Add to Itinerary
                  </button>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem',
    textAlign: 'center'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: '0 0 1rem 0'
  },
  subtitle: {
    color: '#6b7280',
    fontSize: '1.1rem',
    margin: 0
  },
  formContainer: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem'
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '1.5rem'
  },
  formRow: {
    display: 'grid',
    gridTemplateColumns: '1fr 1fr',
    gap: '1.5rem'
  },
  formField: {
    display: 'flex',
    flexDirection: 'column'
  },
  label: {
    marginBottom: '0.5rem',
    fontWeight: '600',
    color: '#374151'
  },
  select: {
    padding: '0.75rem',
    border: '2px solid #e5e7eb',
    borderRadius: '8px',
    fontSize: '1rem'
  },
  input: {
    padding: '0.75rem',
    border: '2px solid #e5e7eb',
    borderRadius: '8px',
    fontSize: '1rem'
  },
  submitButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    border: 'none',
    padding: '1rem 2rem',
    borderRadius: '8px',
    fontSize: '1rem',
    fontWeight: '600',
    cursor: 'pointer',
    alignSelf: 'center'
  },
  resultsContainer: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  resultsTitle: {
    fontSize: '1.5rem',
    fontWeight: '700',
    color: '#1f2937',
    marginBottom: '1.5rem'
  },
  placesGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))',
    gap: '1.5rem'
  },
  placeCard: {
    border: '1px solid #e5e7eb',
    borderRadius: '8px',
    overflow: 'hidden'
  },
  placeImage: {
    width: '100%',
    height: '150px',
    objectFit: 'cover'
  },
  cardContent: {
    padding: '1rem'
  },
  placeName: {
    fontSize: '1.1rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: '0 0 0.5rem 0'
  },
  placeType: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: '0 0 0.5rem 0'
  },
  price: {
    color: '#059669',
    fontWeight: '600',
    margin: '0 0 0.5rem 0'
  },
  rating: {
    color: '#f59e0b',
    fontWeight: '600',
    margin: '0 0 1rem 0'
  },
  addButton: {
    backgroundColor: '#10b981',
    color: 'white',
    border: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '6px',
    cursor: 'pointer',
    fontSize: '0.9rem',
    fontWeight: '600',
    width: '100%'
  }
};

export default BudgetRecommendations;
